import chalk2 from "chalk";
import boxen2 from "boxen";
var createUpdateNotification = (versionNumb) => {
  const line = chalk2.bold.gray("-------------------------------");
  const logo = chalk2.cyan(mentraLogo_1);
  const title = chalk2.bold.cyan(newUpdateText);
  const versionMessage = `Version ${chalk2.bold.cyan(`SDK VERSION V${versionNumb} is out! \uD83C\uDF89`)}`;
  const currentNote = chalk2.yellow("You are running an older version");
  const instructions = chalk2.yellow("Update to the latest version with:");
  const command = chalk2.green.bold("bun install @mentra/sdk@latest");
  const content = [
    logo,
    title,
    line,
    versionMessage,
    currentNote,
    line,
    instructions,
    command
  ].join(`
`);
  return boxen2(content, {
    padding: 1,
    margin: 1,
    borderStyle: "round",
    borderColor: "cyan",
    textAlignment: "left"
  });
};
var newSDKUpdate = (versionNumb) => {
  return createUpdateNotification(versionNumb);
};

